const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const PHONE_REGEX = /^\+[1-9]\d{6,14}$/; // E.164 format

function validateEmail(email) {
    if (!email || typeof email !== 'string') {
        return { valid: false, error: 'Email address is required and must be a string.' };
    }
    const trimmed = email.trim().toLowerCase();
    if (trimmed.length > 254) {
        return { valid: false, error: 'Email address exceeds maximum length.' };
    }
    if (!EMAIL_REGEX.test(trimmed)) {
        return { valid: false, error: 'Invalid email address format.' };
    }
    return { valid: true, value: trimmed };
}

function validatePhone(phone) {
    if (!phone || typeof phone !== 'string') {
        return { valid: false, error: 'Phone number is required and must be a string.' };
    }
    const trimmed = phone.trim().replace(/[\s\-()]/g, '');
    if (!PHONE_REGEX.test(trimmed)) {
        return { valid: false, error: 'Invalid phone number. Use E.164 format (e.g., +14155551234).' };
    }
    return { valid: true, value: trimmed };
}

function validateMessageBody(body, maxLength = 1600) {
    if (!body || typeof body !== 'string') {
        return { valid: false, error: 'Message body is required and must be a string.' };
    }
    const trimmed = body.trim();
    if (trimmed.length === 0) {
        return { valid: false, error: 'Message body cannot be empty.' };
    }
    if (trimmed.length > maxLength) {
        return { valid: false, error: `Message body exceeds maximum length of ${maxLength} characters.` };
    }
    return { valid: true, value: trimmed };
}

function validateSubject(subject) {
    if (!subject || typeof subject !== 'string') {
        return { valid: false, error: 'Subject is required and must be a string.' };
    }
    const trimmed = subject.trim();
    if (trimmed.length === 0 || trimmed.length > 998) {
        return { valid: false, error: 'Subject must be between 1 and 998 characters.' };
    }
    // Strip any potential header injection characters
    const sanitized = trimmed.replace(/[\r\n]/g, ' ');
    return { valid: true, value: sanitized };
}

function isRecipientDomainAllowed(email) {
    const allowedDomains = process.env.ALLOWED_RECIPIENT_DOMAINS;
    if (!allowedDomains) {
        // If no allowlist is configured, allow all (log a warning)
        console.warn(
            'SECURITY WARNING: ALLOWED_RECIPIENT_DOMAINS is not configured. ' +
            'All recipient domains are permitted. Set this in production.'
        );
        return true;
    }
    const domains = allowedDomains.split(',').map(d => d.trim().toLowerCase());
    const recipientDomain = email.split('@')[1];
    return domains.includes(recipientDomain);
}

// ---------------------------------------------------------------------------
// Rate limiting (in-memory, per-instance — use Redis/Azure Cache in production)
// ---------------------------------------------------------------------------
class SimpleRateLimiter {
    constructor(windowMs, maxRequests) {
        this.windowMs = windowMs;
        this.maxRequests = maxRequests;
        this.requests = new Map();
    }

    isAllowed(key) {
        const now = Date.now();
        const windowStart = now - this.windowMs;

        if (!this.requests.has(key)) {
            this.requests.set(key, []);
        }

        const timestamps = this.requests.get(key).filter(ts => ts > windowStart);
        this.requests.set(key, timestamps);

        if (timestamps.length >= this.maxRequests) {
            return false;
        }

        timestamps.push(now);
        return true;
    }

    // Periodic cleanup to prevent memory leaks
    cleanup() {
        const now = Date.now();
        const windowStart = now - this.windowMs;
        for (const [key, timestamps] of this.requests.entries()) {
            const valid = timestamps.filter(ts => ts > windowStart);
            if (valid.length === 0) {
                this.requests.delete(key);
            } else {
                this.requests.set(key, valid);
            }
        }
    }
}

// 10 requests per minute per IP
const rateLimiter = new SimpleRateLimiter(60 * 1000, 10);

// Cleanup every 5 minutes
setInterval(() => rateLimiter.cleanup(), 5 * 60 * 1000);

