// Azure Function: Send Email via SendGrid
// ---------------------------------------------------------------------------
app.http('sendEmail', {
    methods: ['POST'],
    authLevel: 'function', // Requires function key — first line of defense
    route: 'notifications/email',
    handler: async (request, context) => {
        const clientIp = getClientIp(request);
        const requestId = context.invocationId;

        // Rate limiting
        if (!rateLimiter.isAllowed(`email:${clientIp}`)) {
            return errorResponse(429, 'Too many requests. Please try again later.', context);
        }

        // Parse and validate request body
        let body;
        try {
            body = await request.json();
        } catch {
            return errorResponse(400, 'Invalid JSON in request body.', context);
        }

        const { to, subject, text, html } = body || {};

        // Validate inputs
        const toValidation = validateEmail(to);
        if (!toValidation.valid) {
            return errorResponse(400, toValidation.error, context);
        }

        const subjectValidation = validateSubject(subject);
        if (!subjectValidation.valid) {
            return errorResponse(400, subjectValidation.error, context);
        }

        // At least one of text or html must be provided
        if (!text && !html) {
            return errorResponse(400, 'Either "text" or "html" message content is required.', context);
        }

        if (text) {
            const textValidation = validateMessageBody(text, 100000);
            if (!textValidation.valid) {
                return errorResponse(400, textValidation.error, context);
            }
        }

        if (html) {
            const htmlValidation = validateMessageBody(html, 500000);
            if (!htmlValidation.valid) {
                return errorResponse(400, htmlValidation.error, context);
            }
        }

        // Domain allowlist check
        if (!isRecipientDomainAllowed(toValidation.value)) {
            return errorResponse(
                403,
                'Recipient email domain is not in the allowed list.',
                context,
                `Blocked email to ${toValidation.value} — domain not in ALLOWED_RECIPIENT_DOMAINS`
            );
        }

        // Send email
        try {
            const fromEmail = getRequiredEnvVar('SENDGRID_FROM_EMAIL');
            const sgMail = getSendGridClient();

            const msg = {
                to: toValidation.value,
                from: fromEmail,
                subject: subjectValidation.value,
                ...(text && { text: text.trim() }),
                ...(html && { html: html.trim() }),
            };

            const [response] = await sgMail.send(msg);

            context.log.info(
                `[${requestId}] Email sent successfully to ${toValidation.value} ` +
                `(status: ${response.statusCode}, ip: ${clientIp})`
            );

            return successResponse({
                message: 'Email sent successfully.',
                statusCode: response.statusCode,
            });
        } catch (err) {
            // Log full error internally, return safe message to client
            const detail = err.response?.body?.errors
                ? JSON.stringify(err.response.body.errors)
                : err.message;

            return errorResponse(
                502,
                'Failed to send email. Please try again later.',
                context,
                `SendGrid error for ${toValidation.value}: ${detail}`
            );
        }
    },
});

